const items = $input.all();
const body = items[0].json.body;
const data = body.data;

// Validacao do telefone
const telefone = (data.cliente_telefone_e164 || '').toString().trim();
const telefoneValido = /^55\d{2}9\d{8}$/.test(telefone);

if (!telefoneValido) {
  return [{ json: { telefone: '', mensagem: '', erro: 'Telefone invalido ou ausente: ' + (data.cliente_telefone || '(vazio)') + ' -> ' + telefone, enviar: false } }];
}

const nome = data.cliente_nome || 'Cliente';
const order = data.order_number || '';
const cupomUrl = data.cupom_url || '';
const total = data.total ? 'R$ ' + Number(data.total).toFixed(2).replace('.', ',') : '';

const msg = '\ud83e\uddf3 *Cupom do Pedido #' + order + '*\n'
  + '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n\n'
  + 'Ola, ' + nome + '!\n\n'
  + 'Segue o cupom do seu pedido.\n\n'
  + (total ? '\ud83d\udcb0 Total: *' + total + '*\n\n' : '')
  + '\ud83e\uddc3 Ver cupom completo:\n' + cupomUrl + '\n\n'
  + 'Obrigado pela preferencia! \ud83d\ude4f';

return [{ json: { telefone: telefone, mensagem: msg, enviar: true } }];
